// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.459)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.173,0.459,d);}
  col=uColor*(1.9*(0.3+vBlink*0.001));
  col=pow(max(col*vec3(0.83,0.87,0.91),vec3(0.0)),vec3(1.0/1.02));
  {float _gf=exp(-d*7.5)*0.45;col=mix(col,col*2.5,_gf*0.27);}
  alpha=pow(max(alpha,0.0),1.37)*0.25+0.0;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
